import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://api.dev.example.com"
        case .staging:
            return "https://api.stg.example.com"
        case .production:
            return "https://api.example.com"
        }
    }
}

struct UserSession {
    let accessToken: String
}

class APIClient {
    
    static let shared = APIClient()
    
    private let environment: Environment
    private let session = URLSession.shared
    
    init(environment: Environment = .development) {
        self.environment = environment
    }
    
    func authenticate(email: String, password: String, completion: @escaping (Result<UserSession, Error>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/auth") else {
            completion(.failure(NSError(domain: "Invalid URL", code: 0, userInfo: nil)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let authData = ["email": email, "password": password]
        request.httpBody = try? JSONSerialization.data(withJSONObject: authData, options: [])
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "No data received", code: 0, userInfo: nil)))
                return
            }
            
            do {
                let json = try JSONSerialization.jsonObject(with: data, options: []) as? [String: Any]
                if let token = json?["access_token"] as? String {
                    completion(.success(UserSession(accessToken: token)))
                } else {
                    completion(.failure(NSError(domain: "Invalid response", code: 0, userInfo: nil)))
                }
            } catch {
                completion(.failure(error))
            }
        }
        
        task.resume()
    }
    
    func fetchUserData(session: UserSession, completion: @escaping (Result<[String: Any], Error>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/user") else {
            completion(.failure(NSError(domain: "Invalid URL", code: 0, userInfo: nil)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.addValue("Bearer \(session.accessToken)", forHTTPHeaderField: "Authorization")
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "No data received", code: 0, userInfo: nil)))
                return
            }
            
            do {
                let json = try JSONSerialization.jsonObject(with: data, options: []) as? [String: Any]
                if let userData = json {
                    completion(.success(userData))
                } else {
                    completion(.failure(NSError(domain: "Invalid response", code: 0, userInfo: nil)))
                }
            } catch {
                completion(.failure(error))
            }
        }
        
        task.resume()
    }
}

